def calculate_moves(s, target):
    s = list(s)
    moves = 0
    # Find the positions of the target digits
    pos1 = -1
    pos2 = -1
    for i in range(len(s)-1, -1, -1):
        if s[i] == target[1]:
            pos2 = i
            break
    if pos2 == -1:
        return float('inf')
    for i in range(len(s)-1, -1, -1):
        if i != pos2 and s[i] == target[0]:
            pos1 = i
            break
    if pos1 == -1:
        return float('inf')

    # Calculate moves to bring them to the end
    moves = (len(s)-1 - pos2) + (len(s)-2 - pos1) if pos1 < pos2 else (len(s)-1 - pos2) + (len(s)-2 - pos1) + 1

